class Solution:
    def countStableSubarrays(self, capacity):
        n = len(capacity)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + capacity[i]
        cnt = 0
        for l in range(n):
            for r in range(l + 2, n):
                inter = pre[r] - pre[l + 1]
                if capacity[l] == capacity[r] == inter:
                    cnt += 1
        return cnt

