class Solution:
    def countStableSubarrays(self, capacity):
        from collections import defaultdict
        n = len(capacity)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + capacity[i]
        cnt = 0
        seen = defaultdict(int)
        for r in range(n):
            l = r - 2
            if l >= 0:
                seen[(capacity[l], pre[l + 1])] += 1
            if r >= 2:
                cnt += seen[(capacity[r], pre[r] - capacity[r])]
        return cnt

