var countStableSubarrays = function(capacity) {
    const n = capacity.length;
    const pre = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) pre[i + 1] = pre[i] + capacity[i];
    let cnt = 0;
    const seen = new Map();
    for (let r = 0; r < n; r++) {
        const l = r - 2;
        if (l >= 0) {
            const key = capacity[l] + ',' + pre[l + 1];
            seen.set(key, (seen.get(key) || 0) + 1);
        }
        if (r >= 2) {
            const want = capacity[r] + ',' + (pre[r] - capacity[r]);
            cnt += seen.get(want) || 0;
        }
    }
    return cnt;
};
